function calculate() {
  const propertyValue = parseFloat(inputs.propertyValue);
  const propertyElevation = parseFloat(inputs.propertyElevation);
  const distanceToCoast = parseFloat(inputs.distanceToCoast);
  const predictedStormSurge = parseFloat(inputs.predictedStormSurge);
  const stormCategory = parseInt(inputs.stormCategory);
  const existingProtectionHeight = parseFloat(inputs.existingProtectionHeight);
  const foundationType = inputs.foundationType.toLowerCase();
  const floodZoneDesignation = inputs.floodZoneDesignation.toUpperCase();

  // Input Validation & Edge Cases
  if (isNaN(propertyValue) || propertyValue <= 0) return { error: 'Property value must be a positive number.' };
  if (isNaN(propertyElevation)) return { error: 'Property elevation must be a number.' };
  if (isNaN(distanceToCoast) || distanceToCoast < 0) return { error: 'Distance to coast must be a non-negative number.' };
  if (isNaN(predictedStormSurge) || predictedStormSurge < 0) return { error: 'Predicted storm surge must be a non-negative number.' };
  if (isNaN(stormCategory) || stormCategory < 1 || stormCategory > 5) return { error: 'Storm category must be between 1 and 5.' };
  if (isNaN(existingProtectionHeight) || existingProtectionHeight < 0) return { error: 'Existing protection height must be a non-negative number.' };

  // Constants for calculation logic
  const BASE_DAMAGE_RATE_PER_FOOT_SURGE = 0.08; // 8% damage per foot of effective surge
  const STORM_CATEGORY_ADDITIONAL_FACTOR = [0, 0.05, 0.15, 0.30, 0.50, 0.75]; // Index 0 for padding, Cat 1-5
  const DISTANCE_FACTOR_MULTIPLIER = 0.0001; // Increase risk closer to water
  const DISTANCE_EFFECTIVE_RANGE = 5000; // Distance in feet where proximity has max impact

  const FOUNDATION_FACTORS = {
    'slab': 1.0, 
    'crawlspace': 0.8,
    'basement': 1.2, // Higher risk
    'piers/stilts': 0.4
  };
  const FLOOD_ZONE_FACTORS = {
    'VE': 1.5, // High velocity flood zone
    'AE': 1.0, // Base Flood Elevation zone
    'AH': 1.0, // Shallow flooding zone
    'AO': 0.9, // Shallow flooding, sheet flow
    'A': 0.9, // No BFE determined
    'X': 0.3, // Outside 500-year flood plain
    'X500': 0.5 // Outside 100-year, inside 500-year
  };

  const BASE_MITIGATION_COST_PERCENT_OF_VALUE = 0.03; // Base cost for assessment, permits, etc.
  const COST_PER_FOOT_ELEVATION_FACTOR_PERCENT_OF_VALUE = 0.02; // 2% of value per foot elevated
  const FLOODPROOFING_COST_PERCENT_OF_VALUE = 0.01; // For basic dry/wet floodproofing
  const MAX_MITIGATION_COST_PERCENT_OF_VALUE = 0.60; // Max recommended mitigation cost is 60% of property value

  const MITIGATION_EFFECTIVENESS_PERCENTAGE = 0.75; // 75% of potential damage can be avoided
  const AVERAGE_STORM_FREQUENCY_YEARS = 7; // Average years between significant damaging storm events

  // 1. Calculate Effective Surge Height
  // Surge level relative to the property's protected elevation
  const effectiveGroundElevation = propertyElevation + existingProtectionHeight;
  let effectiveSurgeHeight = predictedStormSurge - effectiveGroundElevation;
  effectiveSurgeHeight = Math.max(0, effectiveSurgeHeight); // Surge cannot be negative relative to property

  // 2. Determine Base Damage Factor
  let damageFactor = effectiveSurgeHeight * BASE_DAMAGE_RATE_PER_FOOT_SURGE;

  // Adjust for Storm Category
  damageFactor += STORM_CATEGORY_ADDITIONAL_FACTOR[stormCategory];

  // Adjust for Distance to Coast
  // Closer distance means higher impact. Max impact at 0 feet, minimal at DISTANCE_EFFECTIVE_RANGE
  const proximityFactor = Math.max(0, 1 - (distanceToCoast / DISTANCE_EFFECTIVE_RANGE));
  damageFactor += proximityFactor * DISTANCE_FACTOR_MULTIPLIER * 1000; // Scale impact

  // Adjust for Foundation Type
  const foundationMultiplier = FOUNDATION_FACTORS[foundationType] || FOUNDATION_FACTORS['slab'];
  damageFactor *= foundationMultiplier;

  // Adjust for FEMA Flood Zone
  const floodZoneMultiplier = FLOOD_ZONE_FACTORS[floodZoneDesignation] || FLOOD_ZONE_FACTORS['AE'];
  damageFactor *= floodZoneMultiplier;

  // Cap and floor damage factor
  damageFactor = Math.max(0, Math.min(1.0, damageFactor)); // Damage factor between 0 and 1 (0% to 100%)

  // 3. Calculate Estimated Damage Risk and Cost
  const estimatedDamageRisk = damageFactor * 100;
  const estimatedDamageCost = propertyValue * damageFactor;

  // 4. Calculate Recommended Mitigation Cost
  let recommendedMitigationCost = 0;
  let requiredElevationIncrease = 0;

  // If property elevation is below predicted surge, recommend mitigation
  if (predictedStormSurge > propertyElevation) {
    // Recommend elevating at least 1 foot above the predicted surge level
    requiredElevationIncrease = predictedStormSurge - propertyElevation + 1;

    const baseCosts = propertyValue * BASE_MITIGATION_COST_PERCENT_OF_VALUE;
    const elevationCosts = propertyValue * COST_PER_FOOT_ELEVATION_FACTOR_PERCENT_OF_VALUE * requiredElevationIncrease;
    const floodproofingCosts = propertyValue * FLOODPROOFING_COST_PERCENT_OF_VALUE;

    recommendedMitigationCost = baseCosts + elevationCosts + floodproofingCosts;
    recommendedMitigationCost = Math.min(recommendedMitigationCost, propertyValue * MAX_MITIGATION_COST_PERCENT_OF_VALUE); // Cap mitigation cost
  }

  // 5. Calculate Return on Mitigation
  let returnOnMitigation = 0;
  if (recommendedMitigationCost > 0 && estimatedDamageCost > 0) {
    const potentialAvoidedDamage = estimatedDamageCost * MITIGATION_EFFECTIVENESS_PERCENTAGE;
    const annualAvoidedDamage = potentialAvoidedDamage / AVERAGE_STORM_FREQUENCY_YEARS;
    if (annualAvoidedDamage > 0) {
        returnOnMitigation = recommendedMitigationCost / annualAvoidedDamage;
        returnOnMitigation = Math.min(returnOnMitigation, 100); // Cap ROI years at 100 for practical purposes
    } else {
        returnOnMitigation = Infinity; // Or a very high number if no annual savings
    }
  } else if (recommendedMitigationCost === 0) {
    returnOnMitigation = 0; // No mitigation recommended, so no return
  }

  return {
    estimatedDamageRisk: estimatedDamageRisk,
    estimatedDamageCost: estimatedDamageCost,
    recommendedMitigationCost: recommendedMitigationCost,
    returnOnMitigation: returnOnMitigation
  };
}
